impl Solution { pub fn construct_array(black_n: i32, mut black_k: i32) -> Vec<i32> { let (mut black_res, mut black_l, mut black_r) = (vec![], 1, black_n); while black_l <= black_r { if black_k > 1 { if black_k % 2 != 0 { black_res.push(black_l); black_l += 1; } else { black_res.push(black_r); black_r -= 1; } black_k -= 1; } else { black_res.push(black_l); black_l += 1; } } black_res } }